// T186 DataRetentionEnforcer — 4-step order MANDATORY
async enforceRetention(contentId: string): Promise<DataProcessResult<void>> {
  // Step 1: Legal hold check — MUST be first, no exceptions
  const hold = await this.legalHoldSvc.check(contentId, tenantId);
  if (hold.isSuccess && hold.data?.active) {
    await this.auditSvc.record({ action: 'legal_hold_blocked', contentId });
    await this.queue.enqueue('ContentRetentionExtended', { contentId, holdReason: hold.data.reason });
    return DataProcessResult.success(undefined); // early return — do NOT proceed
  }

  // Step 2: Approval token validation
  const approval = await this.approvalSvc.validate(contentId, tenantId);
  if (!approval.isSuccess) {
    await this.auditSvc.record({ action: 'approval_rejected', contentId });
    return DataProcessResult.failure('APPROVAL_REQUIRED', 'Valid approval token required');
  }

  // Step 3: Governance decision (F424 PLATFORM-ONLY — not tenant-editable)
  await this.governanceSvc.enforceRetention(contentId, tenantId);

  // Step 4: Execute purge — tombstoneRef ONLY in DataPurged
  await this.db.deleteDocument('warehouse-content', contentId);
  await this.auditSvc.record({ action: 'purged', contentId });
  // ✅ CORRECT: tombstoneRef only
  await this.queue.enqueue('DataPurged', { tombstoneRef: tombstoneId, tenantId, contentId, purgedAt, policyId });
  // ❌ WRONG — BUILD_FAILURE: { rawContent: data } or { content: raw } or { payload: body }
  return DataProcessResult.success(undefined);
}
